struct Particle {
    position: vec3f,
    life: f32,
    velocity: vec3f,
    maxLife: f32,
    size: f32,
    opacity: f32,
    pathPhase: f32,
    pathSpread: f32,
    color: vec3f,
    seed: f32,
};

struct SimUniforms {
    count: u32,
    dt: f32,
    time: f32,
    gravity: f32,
    emitterPos: vec3f,
    spawnRadius: f32,
    drag: f32,
    emitSpread: f32,
    motionMode: f32,
    lifeStartMin: f32,
    lifeStartMax: f32,
    lifeEndMin: f32,
    lifeEndMax: f32,
    lifeRandom: f32,
    lifeEasing: f32,
    sizeStartMin: f32,
    sizeStartMax: f32,
    sizeEndMin: f32,
    sizeEndMax: f32,
    sizeRandom: f32,
    sizeEasing: f32,
    opacityStartMin: f32,
    opacityStartMax: f32,
    opacityEndMin: f32,
    opacityEndMax: f32,
    opacityRandom: f32,
    opacityEasing: f32,
    velocityXStartMin: f32,
    velocityXStartMax: f32,
    velocityXEndMin: f32,
    velocityXEndMax: f32,
    velocityXRandom: f32,
    velocityXEasing: f32,
    velocityYStartMin: f32,
    velocityYStartMax: f32,
    velocityYEndMin: f32,
    velocityYEndMax: f32,
    velocityYRandom: f32,
    velocityYEasing: f32,
    velocityZStartMin: f32,
    velocityZStartMax: f32,
    velocityZEndMin: f32,
    velocityZEndMax: f32,
    velocityZRandom: f32,
    velocityZEasing: f32,
    colorStart: vec3f,
    colorEnd: vec3f,
    colorRandom: f32,
    colorRandomBetween: f32,
    colorEasing: f32,
    colorKeyCount: f32,
    _colorPad0: f32,
    _colorPad1: f32,
    _colorPad2: f32,
    colorKey0: vec4f,
    colorKey1: vec4f,
    colorKey2: vec4f,
    colorKey3: vec4f,
    emitShape: f32,
    collisionMode: f32,
    groundY: f32,
    bounce: f32,
    groundFriction: f32,
    boundsHalfX: f32,
    boundsHalfY: f32,
    boundsHalfZ: f32,
    boundsRadius: f32,
    selfCollide: f32,
    boidsNeighborRadius: f32,
    boidsSeparation: f32,
    boidsAlignment: f32,
    boidsCohesion: f32,
    boidsMaxSpeed: f32,
    hairLength: f32,
    hairSegments: f32,
    hairStiffness: f32,
    hairGravity: f32,
    hairGrowth: f32,
    hairRandomTilt: f32,
    fluidGridSize: f32,
    fluidStiffness: f32,
    fluidRestDensity: f32,
    fluidViscosity: f32,
    noiseLayerCount: f32,
    noiseLayers: array<vec4f, 8>,
};

struct PathStorage {
    pointCount: u32,
    tension: f32,
    divergence: f32,
    divergenceStart: f32,
    divergenceEnd: f32,
    followMode: f32,
    spiralTurns: f32,
    spiralRadius: f32,
    _pad3: f32,
    _pad0: f32,
    _pad1: f32,
    _pad2: f32,
    points: array<vec4f, 12>,
};

@group(0) @binding(0) var<uniform> ub: SimUniforms;
@group(0) @binding(1) var<storage, read_write> particles: array<Particle>;
@group(0) @binding(2) var<storage, read> pathData: PathStorage;
@group(0) @binding(3) var<storage, read_write> mpmC: array<mat3x3<f32>>;
@group(0) @binding(4) var<storage, read_write> mpmCells: array<atomic<i32>>;
@group(0) @binding(5) var<storage, read_write> mpmCellsFloat: array<vec4<f32>>;

const MPM_FIXED_POINT: f32 = 10000000.0;

fn rand1(seed: u32) -> f32 {
    var x = seed * 747796405u + 2891336453u;
    x = ((x >> ((x >> 28u) + 4u)) ^ x) * 277803737u;
    return f32((x ^ (x >> 22u))) / 4294967295.0;
}

fn ease(t: f32, mode: i32) -> f32 {
    let c = clamp(t, 0.0, 1.0);
    switch mode {
        case 1: { return c * c; }
        case 2: { let u = 1.0 - c; return 1.0 - u * u; }
        case 3: {
            if (c < 0.5) { return 2.0 * c * c; }
            let u = -2.0 * c + 2.0;
            return 1.0 - u * u * 0.5;
        }
        case 4: { return c * c; }
        case 5: { let u = 1.0 - c; return 1.0 - u * u; }
        case 6: {
            if (c < 0.5) { return 2.0 * c * c; }
            let u = -2.0 * c + 2.0;
            return 1.0 - u * u * 0.5;
        }
        default: { return c; }
    }
}

fn sampleRange(minV: f32, maxV: f32, rnd: f32, random: f32) -> f32 {
    if (random > 0.5) { return mix(minV, maxV, rnd); }
    return minV;
}

fn curveScalar(sm: f32, sx: f32, em: f32, ex: f32, rnd: f32, random: f32, t: f32, easing: f32) -> f32 {
    let start = sampleRange(sm, sx, rnd, random);
    let end = sampleRange(em, ex, fract(rnd * 7.13), random);
    return mix(start, end, ease(t, i32(easing)));
}

fn particleLifeT(life: f32, maxLife: f32) -> f32 {
    if (maxLife <= 0.0) { return 0.0; }
    return 1.0 - clamp(life / max(maxLife, 0.0001), 0.0, 1.0);
}

fn getColorKey(i: i32) -> vec4f {
    switch i {
        case 0: { return ub.colorKey0; }
        case 1: { return ub.colorKey1; }
        case 2: { return ub.colorKey2; }
        default: { return ub.colorKey3; }
    }
}

fn sampleColorKeys(t: f32, easing: f32) -> vec3f {
    let count = max(i32(ub.colorKeyCount), 2);
    var seg = 0;
    for (var i = 0; i < 3; i++) {
        if (i + 1 >= count) { break; }
        let a = getColorKey(i);
        let b = getColorKey(i + 1);
        if (t >= a.x && t <= b.x) { seg = i; break; }
        if (i == count - 2) { seg = i; }
    }
    let ka = getColorKey(seg);
    let kb = getColorKey(min(seg + 1, count - 1));
    let localT = (t - ka.x) / max(kb.x - ka.x, 0.0001);
    return mix(ka.yzw, kb.yzw, ease(localT, i32(easing)));
}

fn curveColor(rnd: f32, rnd2: f32, random: f32, between: f32, t: f32, easing: f32) -> vec3f {
    if (random < 0.5 && between < 0.5) { return sampleColorKeys(t, easing); }
    var c0 = sampleColorKeys(0.0, easing);
    var c1 = sampleColorKeys(t, easing);
    if (random > 0.5) { c0 = mix(sampleColorKeys(0.0, easing), sampleColorKeys(1.0, easing), rnd); }
    if (between > 0.5) { c1 = mix(sampleColorKeys(0.0, easing), sampleColorKeys(1.0, easing), rnd2); }
    return mix(c0, c1, ease(t, i32(easing)));
}

fn getPathPoint(i: i32) -> vec3f {
    let n = i32(pathData.pointCount);
    let idx = clamp(i, 0, max(n - 1, 0));
    return pathData.points[idx].xyz;
}

fn catmullRom(p0: vec3f, p1: vec3f, p2: vec3f, p3: vec3f, t: f32, tension: f32) -> vec3f {
    let s = tension;
    let t2 = t * t;
    let t3 = t2 * t;
    return 0.5 * (
        (2.0 * p1) +
        (-s * p0 + s * p2) * t +
        (2.0 * s * p0 + (s - 6.0) * p1 + (6.0 - 2.0 * s) * p2 + (-s) * p3) * t2 +
        (-s * p0 + (3.0 - s) * p1 + (s - 3.0) * p2 + s * p3) * t3
    );
}

fn cubicBezier(p0: vec3f, c0: vec3f, c1: vec3f, p1: vec3f, t: f32) -> vec3f {
    let u = 1.0 - t;
    return u * u * u * p0 + 3.0 * u * u * t * c0 + 3.0 * u * t * t * c1 + t * t * t * p1;
}

fn pathEdgeFade(t: f32) -> f32 {
    let u = clamp(t, 0.0, 1.0);
    return smoothstep(0.0, 0.05, u) * (1.0 - smoothstep(0.95, 1.0, u));
}

fn samplePathPos(t: f32) -> vec3f {
    let n = i32(pathData.pointCount);
    if (n < 2) { return vec3f(0.0); }
    let u = clamp(t, 0.0, 1.0);
    let ft = u * f32(n - 1);
    let seg = min(i32(floor(ft)), n - 2);
    let lt = clamp(ft - f32(seg), 0.0, 1.0);
    let p0 = getPathPoint(seg);
    let p1 = getPathPoint(seg + 1);
    let prev = getPathPoint(seg - 1);
    let next = getPathPoint(seg + 2);
    let s = pathData.tension * 0.5;
    let c0 = p0 + (p1 - prev) * s / 3.0;
    let c1 = p1 - (next - p0) * s / 3.0;
    return cubicBezier(p0, c0, c1, p1, lt);
}

fn samplePathTangent(t: f32) -> vec3f {
    let eps = 0.002;
    let a = samplePathPos(max(t - eps, 0.0));
    let b = samplePathPos(min(t + eps, 1.0));
    let d = b - a;
    let len = length(d);
    if (len < 0.0001) { return vec3f(0.0, 1.0, 0.0); }
    return d / len;
}

struct PathFrame {
    right: vec3f,
    binorm: vec3f,
};

fn pathFrame(tangent: vec3f) -> PathFrame {
    var up = vec3f(0.0, 1.0, 0.0);
    if (abs(dot(tangent, up)) > 0.95) { up = vec3f(1.0, 0.0, 0.0); }
    let right = normalize(cross(tangent, up));
    return PathFrame(right, cross(tangent, right));
}

fn pathOffset(tangent: vec3f, t: f32, phase: f32, spread: f32) -> vec3f {
    let frame = pathFrame(tangent);
    let right = frame.right;
    let binorm = frame.binorm;
    let along = mix(pathData.divergenceStart, pathData.divergenceEnd, clamp(t, 0.0, 1.0));
    let baseRadius = pathData.divergence * spread * along;
    let mode = i32(round(pathData.followMode));

    switch mode {
        case 1: {
            let angle = phase + pathData.spiralTurns * t * 6.2831853;
            let radius = pathData.spiralRadius * spread * along;
            return (right * cos(angle) + binorm * sin(angle)) * radius;
        }
        case 2: {
            let wave = sin(pathData.spiralTurns * t * 6.2831853);
            let amp = pathData.spiralRadius * spread * along;
            let ring = baseRadius * 0.35;
            return right * (wave * amp + cos(phase) * ring) + binorm * (sin(phase) * ring);
        }
        case 3: {
            let width = max(pathData.spiralRadius, 0.05);
            let u = spread * 2.0 - 1.0;
            return right * (u * baseRadius * width);
        }
        case 4: {
            let points = max(pathData.spiralTurns, 3.0);
            let pointy = clamp(pathData.spiralRadius, 0.0, 1.0);
            let rose = 0.5 + 0.5 * abs(cos(points * phase));
            let radius = baseRadius * mix(1.0, rose, pointy);
            return (right * cos(phase) + binorm * sin(phase)) * radius;
        }
        case 5: {
            let breathe = 0.5 + 0.5 * sin(pathData.spiralTurns * t * 6.2831853);
            let depth = clamp(pathData.spiralRadius, 0.0, 1.0);
            let radius = baseRadius * (1.0 - depth + depth * breathe);
            return (right * cos(phase) + binorm * sin(phase)) * radius;
        }
        default: {
            return (right * cos(phase) + binorm * sin(phase)) * baseRadius;
        }
    }
}

fn sampleVelocity(rnd0: f32, rnd1: f32, rnd2: f32, t: f32) -> vec3f {
    return vec3f(
        curveScalar(ub.velocityXStartMin, ub.velocityXStartMax, ub.velocityXEndMin, ub.velocityXEndMax, rnd0, ub.velocityXRandom, t, ub.velocityXEasing),
        curveScalar(ub.velocityYStartMin, ub.velocityYStartMax, ub.velocityYEndMin, ub.velocityYEndMax, rnd1, ub.velocityYRandom, t, ub.velocityYEasing),
        curveScalar(ub.velocityZStartMin, ub.velocityZStartMax, ub.velocityZEndMin, ub.velocityZEndMax, rnd2, ub.velocityZRandom, t, ub.velocityZEasing),
    );
}

fn spawnOffset(r4: f32, r5: f32, r6: f32) -> vec3f {
    if (ub.spawnRadius <= 0.0) { return vec3f(0.0); }
    let r = ub.spawnRadius;
    let shape = i32(round(ub.emitShape));
    if (shape == 1) {
        var dir = vec3f(r4 * 2.0 - 1.0, r5 * 2.0 - 1.0, r6 * 2.0 - 1.0);
        let len = length(dir);
        if (len > 0.0001) { dir /= len; } else { dir = vec3f(0.0, 1.0, 0.0); }
        return dir * (pow(r6, 1.0 / 3.0) * r);
    }
    if (shape == 2) {
        return vec3f((r4 - 0.5) * 2.0 * r, (r5 - 0.5) * 2.0 * r, (r6 - 0.5) * 2.0 * r);
    }
    if (shape == 3) {
        return vec3f((r4 - 0.5) * 2.0 * r, 0.0, (r5 - 0.5) * 2.0 * r);
    }
    return vec3f(0.0);
}

fn bounceAxis(p: ptr<function, Particle>, axis: i32, outward: f32) {
    let bounce = ub.bounce;
    let fric = clamp(1.0 - ub.groundFriction, 0.0, 1.0);
    var v = (*p).velocity;
    if (axis == 0) {
        if (outward > 0.0 && v.x < 0.0) { v.x = -v.x * bounce; }
        else if (outward < 0.0 && v.x > 0.0) { v.x = -v.x * bounce; }
        v.y *= fric;
        v.z *= fric;
    } else if (axis == 1) {
        if (outward > 0.0 && v.y < 0.0) { v.y = -v.y * bounce; }
        else if (outward < 0.0 && v.y > 0.0) { v.y = -v.y * bounce; }
        v.x *= fric;
        v.z *= fric;
    } else {
        if (outward > 0.0 && v.z < 0.0) { v.z = -v.z * bounce; }
        else if (outward < 0.0 && v.z > 0.0) { v.z = -v.z * bounce; }
        v.x *= fric;
        v.y *= fric;
    }
    (*p).velocity = v;
}

fn bounceNormal(p: ptr<function, Particle>, n: vec3f) {
    let bounce = ub.bounce;
    let fric = clamp(1.0 - ub.groundFriction, 0.0, 1.0);
    let normal = normalize(n);
    let vn = dot((*p).velocity, normal);
    if (vn > 0.0) {
        (*p).velocity = (*p).velocity - normal * vn * (1.0 + bounce);
    }
    let vt = (*p).velocity - normal * dot((*p).velocity, normal);
    (*p).velocity = normal * dot((*p).velocity, normal) + vt * fric;
}

fn boundsHalfBox() -> vec3f {
    return vec3f(
        max(ub.boundsHalfX, 0.01),
        max(ub.boundsHalfY, 0.01),
        max(ub.boundsHalfZ, 0.01),
    );
}

fn boundsSphereRadius() -> f32 {
    return max(ub.boundsRadius, 0.01);
}

fn boundsHasVolume() -> bool {
    let h = boundsHalfBox();
    return max(max(h.x, h.y), max(h.z, boundsSphereRadius())) > 0.01;
}

fn boundsBoxCenter() -> vec3f {
    let h = boundsHalfBox();
    return vec3f(ub.emitterPos.x, ub.groundY + h.y, ub.emitterPos.z);
}

fn boundsSphereCenter() -> vec3f {
    let r = boundsSphereRadius();
    return vec3f(ub.emitterPos.x, ub.groundY + r, ub.emitterPos.z);
}

fn applyBoundsCollision(p: ptr<function, Particle>) {
    let mode = i32(round(ub.collisionMode));
    if (mode == 0) { return; }

    if (mode == 1) {
        if ((*p).position.y < ub.groundY) {
            (*p).position.y = ub.groundY;
            bounceAxis(p, 1, 1.0);
        }
        return;
    }

    if (mode == 2) {
        let half = boundsHalfBox();
        let base = boundsBoxCenter();
        let minB = base - half;
        let maxB = base + half;
        var pos = (*p).position;
        if (pos.x < minB.x) { pos.x = minB.x; bounceAxis(p, 0, 1.0); }
        else if (pos.x > maxB.x) { pos.x = maxB.x; bounceAxis(p, 0, -1.0); }
        if (pos.y < minB.y) { pos.y = minB.y; bounceAxis(p, 1, 1.0); }
        else if (pos.y > maxB.y) { pos.y = maxB.y; bounceAxis(p, 1, -1.0); }
        if (pos.z < minB.z) { pos.z = minB.z; bounceAxis(p, 2, 1.0); }
        else if (pos.z > maxB.z) { pos.z = maxB.z; bounceAxis(p, 2, -1.0); }
        (*p).position = pos;
        return;
    }

    if (mode == 3) {
        let base = boundsSphereCenter();
        let radius = boundsSphereRadius();
        let rel = (*p).position - base;
        let dist = length(rel);
        if (dist > radius && dist > 0.0001) {
            let n = rel / dist;
            (*p).position = base + n * radius;
            bounceNormal(p, n);
        }
    }
}

fn applyFluidSelfCollide(i: u32, p: ptr<function, Particle>) {
    if (ub.selfCollide < 0.5) { return; }
    let h = max((*p).size * 2.5, 0.02);
    var disp = vec3f(0.0);
    var velBounce = vec3f(0.0);
    let bounce = ub.bounce;
    let checks = 24u;
    for (var k = 0u; k < checks; k++) {
        let hash = rand1(i * 131u + k * 9176u + u32(ub.time * 10.0));
        let j = min(u32(hash * f32(max(ub.count, 1u))), ub.count - 1u);
        if (j == i) { continue; }
        let other = particles[j];
        if (other.life <= 0.0) { continue; }
        let d = (*p).position - other.position;
        let dist2 = dot(d, d);
        if (dist2 < 0.000001) { continue; }
        let dist = sqrt(dist2);
        let r1 = max((*p).size, 0.01);
        let r2 = max(other.size, 0.01);
        let minDist = (r1 + r2) * 0.9;
        if (dist < minDist) {
            let n = d / dist;
            disp += n * (minDist - dist);
            let vn = dot((*p).velocity, n);
            if (vn < 0.0) {
                velBounce -= n * vn * (1.0 + bounce);
            }
        } else if (dist < h) {
            let q = 1.0 - dist / h;
            disp += (d / dist) * (q * q * 0.12 * h);
        }
    }
    (*p).position += disp * 0.45;
    (*p).velocity += disp * min(3.0, 1.0 / max(ub.dt, 0.008));
    (*p).velocity += velBounce * 0.5;
}

fn mpmGridDim() -> u32 {
    return max(u32(round(ub.fluidGridSize)), 8u);
}

fn mpmCellCount() -> u32 {
    let g = mpmGridDim();
    return g * g * g;
}

fn mpmEncodeFixed(v: f32) -> i32 {
    return i32(clamp(v * MPM_FIXED_POINT, -2147480000.0, 2147480000.0));
}

fn mpmDecodeFixed(v: i32) -> f32 {
    return f32(v) / MPM_FIXED_POINT;
}

fn fluidBoundsHalfScalar() -> f32 {
    let h = boundsHalfBox();
    return max(max(h.x, h.y), max(h.z, boundsSphereRadius()));
}

fn fluidBoundsBase() -> vec3f {
    let mode = fluidEffectiveCollisionMode();
    if (mode == 3) {
        return boundsSphereCenter();
    }
    return boundsBoxCenter();
}

fn fluidDomainMin() -> vec3f {
    let mode = fluidEffectiveCollisionMode();
    if (mode == 3) {
        let base = boundsSphereCenter();
        let r = boundsSphereRadius();
        return base - vec3f(r);
    }
    let base = boundsBoxCenter();
    return base - boundsHalfBox();
}

fn fluidDomainSize() -> f32 {
    return max(fluidBoundsHalfScalar() * 2.0, 0.02);
}

fn worldToNorm(worldPos: vec3f) -> vec3f {
    return (worldPos - fluidDomainMin()) / max(fluidDomainSize(), 0.01);
}

fn normToWorld(normPos: vec3f) -> vec3f {
    return fluidDomainMin() + normPos * fluidDomainSize();
}

fn fluidWorldToGridVel(worldVel: vec3f, gridDim: f32) -> vec3f {
    return worldVel * gridDim / max(fluidDomainSize(), 0.01);
}

fn fluidGridToWorldVel(gridVel: vec3f, gridDim: f32) -> vec3f {
    return gridVel * fluidDomainSize() / gridDim;
}

fn fluidSpawnNorm(r4: f32, r5: f32, r6: f32) -> vec3f {
    return vec3f(r4 * 0.8 + 0.1, r5 * 0.8 + 0.1, r6 * 0.8 + 0.1);
}

fn fluidEffectiveCollisionMode() -> i32 {
    let mode = i32(round(ub.collisionMode));
    if (mode != 0) { return mode; }
    if (boundsHasVolume()) { return 2; }
    return 0;
}

fn fluidClampWorldPos(pos: vec3f) -> vec3f {
    let mode = fluidEffectiveCollisionMode();
    var result = pos;

    if (mode == 1) {
        if (result.y < ub.groundY) { result.y = ub.groundY; }
        return result;
    }

    let half = boundsHalfBox();
    let base = boundsBoxCenter();
    let sphereR = boundsSphereRadius();

    if (mode == 3) {
        let sphereBase = boundsSphereCenter();
        let rel = result - sphereBase;
        let dist = length(rel);
        if (dist > sphereR && dist > 0.0001) {
            result = sphereBase + (rel / dist) * sphereR;
        }
        return result;
    }

    if (mode == 2) {
        let minB = base - half;
        let maxB = base + half;
        return clamp(result, minB, maxB);
    }

    return result;
}

fn fluidSpawnWorld(r4: f32, r5: f32, r6: f32) -> vec3f {
    let mode = fluidEffectiveCollisionMode();
    let half = boundsHalfBox();
    let base = boundsBoxCenter();
    let sphereR = boundsSphereRadius();

    if (mode == 3) {
        let sphereBase = boundsSphereCenter();
        let theta = r4 * 6.2831853;
        let phi = acos(clamp(r5 * 2.0 - 1.0, -1.0, 1.0));
        let radius = pow(r6, 1.0 / 3.0) * sphereR * 0.85;
        let offset = vec3f(
            sin(phi) * cos(theta),
            cos(phi),
            sin(phi) * sin(theta),
        ) * radius;
        return sphereBase + offset;
    }

    if (mode == 1) {
        let minB = base - half;
        return vec3f(
            minB.x + r4 * half.x * 2.0,
            ub.groundY + r5 * half.y * 0.85,
            minB.z + r6 * half.z * 2.0,
        );
    }

    return normToWorld(fluidSpawnNorm(r4, r5, r6));
}

fn mpmClampToRoundedBox(pos: vec3f, boxHalf: vec3f, radius: f32) -> vec3f {
    var result = pos - vec3f(0.5);
    let absResult = abs(result);
    var pp = vec3f(0.0);
    if (absResult.x > boxHalf.x) {
        pp.x = (absResult.x - boxHalf.x) * sign(result.x);
    }
    if (absResult.y > boxHalf.y) {
        pp.y = (absResult.y - boxHalf.y) * sign(result.y);
    }
    if (absResult.z > boxHalf.z) {
        pp.z = (absResult.z - boxHalf.z) * sign(result.z);
    }
    let ppLen = length(pp);
    let dist = ppLen - radius;
    if (dist > 0.0 && ppLen > 0.0001) {
        result -= (pp / ppLen) * dist * 1.3;
    }
    return result + vec3f(0.5);
}

fn mpmCellPtr(cell: vec3i) -> u32 {
    let g = i32(mpmGridDim());
    return u32(cell.x * g * g + cell.y * g + cell.z);
}

fn mpmCellInBounds(cell: vec3i) -> bool {
    let g = i32(mpmGridDim());
    return cell.x >= 0 && cell.y >= 0 && cell.z >= 0
        && cell.x < g && cell.y < g && cell.z < g;
}

fn mpmAtomicAddCell(cellPtr: u32, slot: u32, value: f32) {
    let idx = cellPtr * 4u + slot;
    atomicAdd(&mpmCells[idx], mpmEncodeFixed(value));
}

fn mpmWeight(w0: vec3f, w1: vec3f, w2: vec3f, gx: i32, gy: i32, gz: i32) -> f32 {
    var wx = w0.x;
    var wy = w0.y;
    var wz = w0.z;
    if (gx == 1) { wx = w1.x; } else if (gx == 2) { wx = w2.x; }
    if (gy == 1) { wy = w1.y; } else if (gy == 2) { wy = w2.y; }
    if (gz == 1) { wz = w1.z; } else if (gz == 2) { wz = w2.z; }
    return wx * wy * wz;
}

@compute @workgroup_size(64)
fn clearMpmGrid(@builtin(global_invocation_id) gid: vec3u) {
    let i = gid.x * 1024u + gid.y;
    let count = mpmCellCount();
    if (i >= count) { return; }
    atomicStore(&mpmCells[i * 4u + 0u], 0);
    atomicStore(&mpmCells[i * 4u + 1u], 0);
    atomicStore(&mpmCells[i * 4u + 2u], 0);
    atomicStore(&mpmCells[i * 4u + 3u], 0);
    mpmCellsFloat[i] = vec4f(0.0);
}

@compute @workgroup_size(64)
fn mpmP2G1(@builtin(global_invocation_id) gid: vec3u) {
    let i = gid.x * 1024u + gid.y;
    if (i >= ub.count) { return; }
    let p = particles[i];
    if (p.life <= 0.0) { return; }

    let normPos = worldToNorm(p.position);
    let gridDim = f32(mpmGridDim());
    let gridPos = normPos * gridDim;
    let cellIndex = vec3i(gridPos) - vec3i(1);
    let cellDiff = fract(gridPos) - vec3f(0.5);
    let w0 = 0.5 * (0.5 - cellDiff) * (0.5 - cellDiff);
    let w1 = 0.75 - cellDiff * cellDiff;
    let w2 = 0.5 * (0.5 + cellDiff) * (0.5 + cellDiff);
    let C = mpmC[i];
    let gridVel = fluidWorldToGridVel(p.velocity, gridDim);

    for (var gx = 0; gx < 3; gx++) {
        for (var gy = 0; gy < 3; gy++) {
            for (var gz = 0; gz < 3; gz++) {
                let weight = mpmWeight(w0, w1, w2, gx, gy, gz);
                let cell = cellIndex + vec3i(gx, gy, gz);
                if (!mpmCellInBounds(cell)) { continue; }
                let cellDist = vec3f(cell) + vec3f(0.5) - gridPos;
                let Q = C * cellDist;
                let massContrib = weight;
                let velContrib = massContrib * (gridVel + Q);
                let ptr = mpmCellPtr(cell);
                mpmAtomicAddCell(ptr, 0u, velContrib.x);
                mpmAtomicAddCell(ptr, 1u, velContrib.y);
                mpmAtomicAddCell(ptr, 2u, velContrib.z);
                mpmAtomicAddCell(ptr, 3u, massContrib);
            }
        }
    }
}

@compute @workgroup_size(64)
fn mpmP2G2(@builtin(global_invocation_id) gid: vec3u) {
    let i = gid.x * 1024u + gid.y;
    if (i >= ub.count) { return; }
    let p = particles[i];
    if (p.life <= 0.0) { return; }

    let normPos = worldToNorm(p.position);
    let gridDim = f32(mpmGridDim());
    let gridPos = normPos * gridDim;
    let cellIndex = vec3i(gridPos) - vec3i(1);
    let cellDiff = fract(gridPos) - vec3f(0.5);
    let w0 = 0.5 * (0.5 - cellDiff) * (0.5 - cellDiff);
    let w1 = 0.75 - cellDiff * cellDiff;
    let w2 = 0.5 * (0.5 + cellDiff) * (0.5 + cellDiff);
    let C = mpmC[i];
    let dt = ub.dt;

    var density = 0.0;
    for (var gx = 0; gx < 3; gx++) {
        for (var gy = 0; gy < 3; gy++) {
            for (var gz = 0; gz < 3; gz++) {
                let weight = mpmWeight(w0, w1, w2, gx, gy, gz);
                let cell = cellIndex + vec3i(gx, gy, gz);
                if (!mpmCellInBounds(cell)) { continue; }
                let ptr = mpmCellPtr(cell);
                let mass = mpmDecodeFixed(atomicLoad(&mpmCells[ptr * 4u + 3u]));
                density += mass * weight;
            }
        }
    }

    let rest = max(ub.fluidRestDensity, 0.01);
    let volume = 1.0 / max(density, 0.0001);
    let pressure = max(0.0, pow(density / rest, 5.0) - 1.0) * ub.fluidStiffness;
    var stress = mat3x3<f32>(
        vec3f(-pressure, 0.0, 0.0),
        vec3f(0.0, -pressure, 0.0),
        vec3f(0.0, 0.0, -pressure),
    );
    let strain = C + transpose(C);
    stress += strain * ub.fluidViscosity;
    let eq16Term0 = volume * (-4.0) * stress * dt;

    for (var gx = 0; gx < 3; gx++) {
        for (var gy = 0; gy < 3; gy++) {
            for (var gz = 0; gz < 3; gz++) {
                let weight = mpmWeight(w0, w1, w2, gx, gy, gz);
                let cell = cellIndex + vec3i(gx, gy, gz);
                if (!mpmCellInBounds(cell)) { continue; }
                let cellDist = vec3f(cell) + vec3f(0.5) - gridPos;
                let momentum = eq16Term0 * weight * cellDist;
                let ptr = mpmCellPtr(cell);
                mpmAtomicAddCell(ptr, 0u, momentum.x);
                mpmAtomicAddCell(ptr, 1u, momentum.y);
                mpmAtomicAddCell(ptr, 2u, momentum.z);
            }
        }
    }
}

@compute @workgroup_size(64)
fn mpmUpdateGrid(@builtin(global_invocation_id) gid: vec3u) {
    let i = gid.x * 1024u + gid.y;
    let count = mpmCellCount();
    if (i >= count) { return; }

    let mass = mpmDecodeFixed(atomicLoad(&mpmCells[i * 4u + 3u]));
    if (mass <= 0.0) { return; }

    var vx = mpmDecodeFixed(atomicLoad(&mpmCells[i * 4u + 0u])) / mass;
    var vy = mpmDecodeFixed(atomicLoad(&mpmCells[i * 4u + 1u])) / mass;
    var vz = mpmDecodeFixed(atomicLoad(&mpmCells[i * 4u + 2u])) / mass;

    let g = i32(mpmGridDim());
    let cx = i32(i) / (g * g);
    let cy = (i32(i) / g) % g;
    let cz = i32(i) % g;

    if (cx <= 0 || cx >= g - 1) { vx = 0.0; }
    if (cy <= 0 || cy >= g - 1) { vy = 0.0; }
    if (cz <= 0 || cz >= g - 1) { vz = 0.0; }

    mpmCellsFloat[i] = vec4f(vx, vy, vz, mass);
}

@compute @workgroup_size(64)
fn mpmG2P(@builtin(global_invocation_id) gid: vec3u) {
    let i = gid.x * 1024u + gid.y;
    if (i >= ub.count) { return; }
    var p = particles[i];
    if (p.life <= 0.0) { return; }

    let gridDim = f32(mpmGridDim());
    var normPos = worldToNorm(p.position);
    let gridPos = normPos * gridDim;
    let cellIndex = vec3i(gridPos) - vec3i(1);
    let cellDiff = fract(gridPos) - vec3f(0.5);
    let w0 = 0.5 * (0.5 - cellDiff) * (0.5 - cellDiff);
    let w1 = 0.75 - cellDiff * cellDiff;
    let w2 = 0.5 * (0.5 + cellDiff) * (0.5 + cellDiff);

    var gridVel = vec3f(0.0);
    var B = mat3x3<f32>();

    for (var gx = 0; gx < 3; gx++) {
        for (var gy = 0; gy < 3; gy++) {
            for (var gz = 0; gz < 3; gz++) {
                let weight = mpmWeight(w0, w1, w2, gx, gy, gz);
                let cell = cellIndex + vec3i(gx, gy, gz);
                if (!mpmCellInBounds(cell)) { continue; }
                let cellDist = vec3f(cell) + vec3f(0.5) - gridPos;
                let ptr = mpmCellPtr(cell);
                let weightedVelocity = mpmCellsFloat[ptr].xyz * weight;
                B += mat3x3<f32>(
                    weightedVelocity * cellDist.x,
                    weightedVelocity * cellDist.y,
                    weightedVelocity * cellDist.z,
                );
                gridVel += weightedVelocity;
            }
        }
    }

    mpmC[i] = B * 4.0;
    gridVel += vec3f(0.0, -ub.gravity * 9.81 * 9.81, 0.0) * ub.dt;
    gridVel *= max(0.0, 1.0 - ub.drag * ub.dt);
    gridVel /= gridDim;
    normPos += gridVel * ub.dt;

    let margin = 1.0 / gridDim;
    normPos = clamp(normPos, vec3f(margin), vec3f(1.0 - margin));

    let innerBox = (vec3f(gridDim) * 0.5 - 9.0) / gridDim;
    let innerRadius = 6.0 / gridDim;
    let posNext = normPos + gridVel * ub.dt * 2.0;
    let collisionMode = fluidEffectiveCollisionMode();
    var posNextClamped = posNext;

    if (collisionMode == 2) {
        posNextClamped = mpmClampToRoundedBox(posNext, innerBox, innerRadius);
    } else if (collisionMode == 3) {
        posNextClamped = worldToNorm(fluidClampWorldPos(normToWorld(posNext)));
    } else if (collisionMode == 1) {
        posNextClamped = worldToNorm(fluidClampWorldPos(normToWorld(posNext)));
        posNextClamped = clamp(posNextClamped, vec3f(margin), vec3f(1.0 - margin));
    } else {
        posNextClamped = clamp(posNext, vec3f(margin), vec3f(1.0 - margin));
    }

    gridVel += posNextClamped - posNext;
    gridVel *= gridDim;

    p.position = fluidClampWorldPos(normToWorld(normPos));
    p.velocity = fluidGridToWorldVel(gridVel, gridDim);
    particles[i] = p;
}

fn hairRootOffset(p: Particle) -> vec3f {
    return vec3f(p.pathPhase, 0.0, p.pathSpread);
}

fn applyHair(p: ptr<function, Particle>) {
    let root = ub.emitterPos + hairRootOffset(*p);
    (*p).position = root;

    let wind = vec3f(
        sin(ub.time * 1.8 + (*p).seed * 0.17) * 0.35,
        0.0,
        cos(ub.time * 1.4 + (*p).seed * 0.23) * 0.35,
    );

    var bend = (*p).velocity;
    let segN = max(i32(round(ub.hairSegments)), 1);
    let segCount = f32(segN);
    let grav = ub.gravity * ub.hairGravity;
    let stiff = clamp(ub.hairStiffness, 0.0, 0.99);
    let dt = ub.dt;

    for (var s = 0; s < segN; s++) {
        let t = (f32(s) + 0.5) / segCount;
        bend.x += (wind.x - grav * t * 0.15) * dt;
        bend.z += wind.z * dt;
        bend.y += sin(ub.time * 2.2 + (*p).seed + t * 3.0) * 0.02 * dt;
    }

    bend *= stiff;
    let maxBend = max(ub.hairRandomTilt, 0.05) * 2.5;
    bend = limitVec3(bend, maxBend);
    (*p).velocity = bend;
}

fn limitVec3(v: vec3f, maxLen: f32) -> vec3f {
    let len = length(v);
    if (len > maxLen && len > 0.0001) {
        return v / len * maxLen;
    }
    return v;
}

fn boidsBoundsHalf() -> vec3f {
    return boundsHalfBox();
}

fn boidsBoundsBase() -> vec3f {
    let mode = boidsEffectiveCollisionMode();
    if (mode == 3) {
        return boundsSphereCenter();
    }
    return boundsBoxCenter();
}

fn boidsEffectiveCollisionMode() -> i32 {
    let mode = i32(round(ub.collisionMode));
    if (mode != 0) { return mode; }
    if (boundsHasVolume()) { return 2; }
    return 0;
}

fn boidsSpawnVolume(r4: f32, r5: f32, r6: f32) -> vec3f {
    if (ub.spawnRadius > 0.0) {
        return spawnOffset(r4, r5, r6);
    }
    let half = boidsBoundsHalf() * 0.82;
    let base = boidsBoundsBase();
    return base - ub.emitterPos + vec3f(
        (r4 - 0.5) * 2.0 * half.x,
        (r5 - 0.5) * 2.0 * half.y,
        (r6 - 0.5) * 2.0 * half.z,
    );
}

fn boidsComputeAlignment(selfPos: vec3f, i: u32, radius: f32) -> vec3f {
    var sumVel = vec3f(0.0);
    var count = 0u;
    let r2 = radius * radius;

    for (var j = 0u; j < ub.count; j++) {
        if (j == i) { continue; }
        let other = particles[j];
        if (other.life <= 0.0) { continue; }
        let diff = selfPos - other.position;
        let dist2 = dot(diff, diff);
        if (dist2 >= r2 || dist2 < 0.000001) { continue; }
        sumVel += other.velocity;
        count++;
    }

    if (count == 0u) { return vec3f(0.0); }
    let avg = sumVel / f32(count);
    let len = length(avg);
    if (len < 0.0001) { return vec3f(0.0); }
    return avg / len;
}

fn boidsComputeCohesion(selfPos: vec3f, i: u32, radius: f32) -> vec3f {
    var center = vec3f(0.0);
    var count = 0u;
    let r2 = radius * radius;

    for (var j = 0u; j < ub.count; j++) {
        if (j == i) { continue; }
        let other = particles[j];
        if (other.life <= 0.0) { continue; }
        let diff = selfPos - other.position;
        let dist2 = dot(diff, diff);
        if (dist2 >= r2 || dist2 < 0.000001) { continue; }
        center += other.position;
        count++;
    }

    if (count == 0u) { return vec3f(0.0); }
    center /= f32(count);
    let toCenter = center - selfPos;
    let len = length(toCenter);
    if (len < 0.0001) { return vec3f(0.0); }
    return toCenter / len;
}

fn boidsComputeSeparation(selfPos: vec3f, i: u32, radius: f32) -> vec3f {
    var sep = vec3f(0.0);

    for (var j = 0u; j < ub.count; j++) {
        if (j == i) { continue; }
        let other = particles[j];
        if (other.life <= 0.0) { continue; }
        let diff = selfPos - other.position;
        let dist2 = dot(diff, diff);
        if (dist2 < 0.000001) { continue; }
        let dist = sqrt(dist2);
        if (dist >= radius) { continue; }
        let d = max(dist, 0.01);
        sep += (diff / d) / d;
    }

    return sep;
}

fn boidsComputeBoundaryAvoid(pos: vec3f, radius: f32) -> vec3f {
    let mode = boidsEffectiveCollisionMode();
    if (mode == 0) { return vec3f(0.0); }

    var avoid = vec3f(0.0);
    let wallRadius = max(radius * 0.25, 0.05);

    if (mode == 1) {
        let distY = pos.y - ub.groundY;
        if (distY < wallRadius && distY > 0.0001) {
            avoid.y += 1.0 / distY;
        }
        return avoid;
    }

    let half = boidsBoundsHalf();
    let base = boidsBoundsBase();
    let sphereR = boundsSphereRadius();

    if (mode == 2) {
        let minB = base - half;
        let maxB = base + half;
        let distMinX = pos.x - minB.x;
        if (distMinX < wallRadius && distMinX > 0.0001) { avoid.x += 1.0 / distMinX; }
        let distMaxX = maxB.x - pos.x;
        if (distMaxX < wallRadius && distMaxX > 0.0001) { avoid.x -= 1.0 / distMaxX; }

        let distMinY = pos.y - minB.y;
        if (distMinY < wallRadius && distMinY > 0.0001) { avoid.y += 1.0 / distMinY; }
        let distMaxY = maxB.y - pos.y;
        if (distMaxY < wallRadius && distMaxY > 0.0001) { avoid.y -= 1.0 / distMaxY; }

        let distMinZ = pos.z - minB.z;
        if (distMinZ < wallRadius && distMinZ > 0.0001) { avoid.z += 1.0 / distMinZ; }
        let distMaxZ = maxB.z - pos.z;
        if (distMaxZ < wallRadius && distMaxZ > 0.0001) { avoid.z -= 1.0 / distMaxZ; }
        return avoid;
    }

    if (mode == 3) {
        let rel = pos - base;
        let dist = length(rel);
        if (dist > 0.0001) {
            let clearance = sphereR - dist;
            if (clearance < wallRadius && clearance > 0.0001) {
                avoid -= normalize(rel) / clearance;
            } else if (clearance <= 0.0001) {
                avoid -= normalize(rel) / max(wallRadius, 0.0001);
            }
        }
    }

    return avoid;
}

fn boidsKillOutwardVelocity(p: ptr<function, Particle>, mode: i32, half: vec3f, sphereR: f32, base: vec3f) {
    var vel = (*p).velocity;

    if (mode == 1) {
        if ((*p).position.y <= ub.groundY + 0.0001 && vel.y < 0.0) {
            vel.y = 0.0;
        }
        (*p).velocity = vel;
        return;
    }

    if (mode == 2) {
        let minB = base - half;
        let maxB = base + half;
        let pos = (*p).position;
        if (pos.x <= minB.x + 0.0001 && vel.x < 0.0) { vel.x = 0.0; }
        if (pos.x >= maxB.x - 0.0001 && vel.x > 0.0) { vel.x = 0.0; }
        if (pos.y <= minB.y + 0.0001 && vel.y < 0.0) { vel.y = 0.0; }
        if (pos.y >= maxB.y - 0.0001 && vel.y > 0.0) { vel.y = 0.0; }
        if (pos.z <= minB.z + 0.0001 && vel.z < 0.0) { vel.z = 0.0; }
        if (pos.z >= maxB.z - 0.0001 && vel.z > 0.0) { vel.z = 0.0; }
        (*p).velocity = vel;
        return;
    }

    if (mode == 3) {
        let rel = (*p).position - base;
        let dist = length(rel);
        if (dist >= sphereR - 0.0001 && dist > 0.0001) {
            let n = rel / dist;
            let vn = dot(vel, n);
            if (vn > 0.0) {
                vel -= n * vn;
            }
        }
        (*p).velocity = vel;
    }
}

fn boidsEnforceBounds(p: ptr<function, Particle>) {
    let mode = boidsEffectiveCollisionMode();
    if (mode == 0) { return; }

    if (mode == 1) {
        if ((*p).position.y < ub.groundY) {
            (*p).position.y = ub.groundY;
        }
        boidsKillOutwardVelocity(p, mode, vec3f(0.0), 0.0, vec3f(0.0));
        return;
    }

    let half = boidsBoundsHalf();
    let base = boidsBoundsBase();
    let sphereR = boundsSphereRadius();

    if (mode == 2) {
        let minB = base - half;
        let maxB = base + half;
        var pos = (*p).position;
        pos = clamp(pos, minB, maxB);
        (*p).position = pos;
        boidsKillOutwardVelocity(p, mode, half, sphereR, base);
        return;
    }

    if (mode == 3) {
        let rel = (*p).position - base;
        let dist = length(rel);
        if (dist > sphereR && dist > 0.0001) {
            (*p).position = base + rel / dist * sphereR;
        }
        boidsKillOutwardVelocity(p, mode, half, sphereR, base);
    }
}

fn applyBoids(i: u32, p: ptr<function, Particle>) {
    let radius = max(ub.boidsNeighborRadius, 0.12);
    let maxSpeed = max(ub.boidsMaxSpeed, 0.05);
    let step = max(ub.dt * 60.0, 0.0001);
    let forceScale = step * (maxSpeed / 5.0);
    let selfPos = (*p).position;

    let align = boidsComputeAlignment(selfPos, i, radius);
    let coh = boidsComputeCohesion(selfPos, i, radius);
    var sep = boidsComputeSeparation(selfPos, i, radius);
    let obs = boidsComputeBoundaryAvoid(selfPos, radius);

    let sepLen = length(sep);
    if (sepLen > 8.0) {
        sep = sep / sepLen * 8.0;
    }

    var vel = (*p).velocity;
    vel += (align * ub.boidsAlignment
          + coh * ub.boidsCohesion
          + sep * ub.boidsSeparation * 50.0
          + obs * 100.0) * forceScale;

    let speed = length(vel);
    if (speed > maxSpeed && speed > 0.0001) {
        vel *= maxSpeed / speed;
    }

    (*p).velocity = vel;
}

const NOISE_TARGET_VELOCITY: i32 = 1;
const NOISE_TARGET_COLOR: i32 = 2;
const NOISE_TARGET_SIZE: i32 = 4;
const NOISE_TARGET_OPACITY: i32 = 8;
const NOISE_TARGET_POSITION: i32 = 16;

fn hash33(p: vec3f) -> vec3f {
    var q = fract(p * vec3f(0.1031, 0.1030, 0.0973));
    q += dot(q, q.yxz + 33.33);
    return fract((q.xxy + q.yxx) * q.zyx);
}

fn hash13(p: vec3f) -> f32 {
    return fract(sin(dot(p, vec3f(127.1, 311.7, 74.7))) * 43758.5453);
}

fn fade3(t: vec3f) -> vec3f {
    return t * t * t * (t * (t * 6.0 - 15.0) + 10.0);
}

fn fade2(t: vec2f) -> vec2f {
    return t * t * t * (t * (t * 6.0 - 15.0) + 10.0);
}

fn vec3mod(v: vec3f, m: f32) -> vec3f {
    return v - floor(v / m) * m;
}

fn grad3(hash: f32, x: f32, y: f32, z: f32) -> f32 {
    let h = i32(hash * 16.0);
    let u = select(y, x, (h & 1) == 0);
    let v = select(select(x, z, (h & 2) == 0), y, (h & 1) != 0);
    return select(u, -u, (h & 4) != 0) + select(v, -v, (h & 8) != 0);
}

fn grad2(hash: f32, x: f32, y: f32) -> f32 {
    let h = i32(hash * 4.0);
    let u = select(y, x, (h & 1) == 0);
    let v = select(x, y, (h & 1) != 0);
    return select(u, -u, (h & 2) != 0) + select(v, -v, (h & 2) != 0);
}

fn noisePerlin3(p: vec3f) -> f32 {
    let i = floor(p);
    let f = fract(p);
    let u = fade3(f);
    let n000 = grad3(hash13(i + vec3f(0.0, 0.0, 0.0)), f.x, f.y, f.z);
    let n100 = grad3(hash13(i + vec3f(1.0, 0.0, 0.0)), f.x - 1.0, f.y, f.z);
    let n010 = grad3(hash13(i + vec3f(0.0, 1.0, 0.0)), f.x, f.y - 1.0, f.z);
    let n110 = grad3(hash13(i + vec3f(1.0, 1.0, 0.0)), f.x - 1.0, f.y - 1.0, f.z);
    let n001 = grad3(hash13(i + vec3f(0.0, 0.0, 1.0)), f.x, f.y, f.z - 1.0);
    let n101 = grad3(hash13(i + vec3f(1.0, 0.0, 1.0)), f.x - 1.0, f.y, f.z - 1.0);
    let n011 = grad3(hash13(i + vec3f(0.0, 1.0, 1.0)), f.x, f.y - 1.0, f.z - 1.0);
    let n111 = grad3(hash13(i + vec3f(1.0, 1.0, 1.0)), f.x - 1.0, f.y - 1.0, f.z - 1.0);
    let x0 = mix(n000, n100, u.x);
    let x1 = mix(n010, n110, u.x);
    let x2 = mix(n001, n101, u.x);
    let x3 = mix(n011, n111, u.x);
    return mix(mix(x0, x1, u.y), mix(x2, x3, u.y), u.z);
}

fn noisePerlin2(p: vec2f) -> f32 {
    let i = floor(p);
    let f = fract(p);
    let u = fade2(f);
    let n00 = grad2(hash13(vec3f(i.x, i.y, 0.0)), f.x, f.y);
    let n10 = grad2(hash13(vec3f(i.x + 1.0, i.y, 0.0)), f.x - 1.0, f.y);
    let n01 = grad2(hash13(vec3f(i.x, i.y + 1.0, 0.0)), f.x, f.y - 1.0);
    let n11 = grad2(hash13(vec3f(i.x + 1.0, i.y + 1.0, 0.0)), f.x - 1.0, f.y - 1.0);
    return mix(mix(n00, n10, u.x), mix(n01, n11, u.x), u.y);
}

fn noiseSimplex2(p: vec2f) -> f32 {
    let s = (p.x + p.y) * 0.366025403;
    let i = floor(p + s);
    let t = (i.x + i.y) * 0.211324865;
    let x0 = p - (i - t);
    let i1 = select(vec2f(0.0, 1.0), vec2f(1.0, 0.0), x0.x > x0.y);
    let x1 = x0 - i1 + 0.211324865;
    let x2 = x0 - 0.577350269;
    let h0 = hash13(vec3f(i.x, i.y, 0.0));
    let h1 = hash13(vec3f(i.x + i1.x, i.y + i1.y, 0.0));
    let h2 = hash13(vec3f(i.x + 1.0, i.y + 1.0, 0.0));
    let g0 = grad2(h0, x0.x, x0.y);
    let g1 = grad2(h1, x1.x, x1.y);
    let g2 = grad2(h2, x2.x, x2.y);
    let m0 = max(0.5 - dot(x0, x0), 0.0);
    let m1 = max(0.5 - dot(x1, x1), 0.0);
    let m2 = max(0.5 - dot(x2, x2), 0.0);
    return 70.0 * (m0 * m0 * m0 * m0 * g0 + m1 * m1 * m1 * m1 * g1 + m2 * m2 * m2 * m2 * g2);
}

fn noiseSimplex3(p: vec3f) -> f32 {
    let K1 = 0.333333333;
    let K2 = 0.166666667;
    let i = floor(p + dot(p, vec3f(K1)));
    let t = dot(i, vec3f(K2));
    let x0 = p - i + t;
    let g = step(x0.yzx, x0.xyz);
    let l = 1.0 - g;
    let i1 = min(g.xyz, l.zxy);
    let i2 = max(g.xyz, l.zxy);
    let x1 = x0 - i1 + K2;
    let x2 = x0 - i2 + 2.0 * K2;
    let x3 = x0 - 1.0 + 3.0 * K2;
    let ii = vec3mod(i, 289.0);
    let m0 = max(0.6 - dot(x0, x0), 0.0);
    let m1 = max(0.6 - dot(x1, x1), 0.0);
    let m2 = max(0.6 - dot(x2, x2), 0.0);
    let m3 = max(0.6 - dot(x3, x3), 0.0);
    let m = vec4f(m0 * m0 * m0 * m0, m1 * m1 * m1 * m1, m2 * m2 * m2 * m2, m3 * m3 * m3 * m3);
    let g0 = hash33(ii) * 2.0 - 1.0;
    let g1 = hash33(ii + i1) * 2.0 - 1.0;
    let g2 = hash33(ii + i2) * 2.0 - 1.0;
    let g3 = hash33(ii + 1.0) * 2.0 - 1.0;
    return 42.0 * (
        m.x * dot(g0, x0) + m.y * dot(g1, x1) + m.z * dot(g2, x2) + m.w * dot(g3, x3)
    );
}

fn voronoi3(p: vec3f) -> f32 {
    let n = floor(p);
    let f = fract(p);
    var md = 8.0;
    for (var k = -1; k <= 1; k++) {
        for (var j = -1; j <= 1; j++) {
            for (var i = -1; i <= 1; i++) {
                let g = vec3f(f32(i), f32(j), f32(k));
                let o = hash33(n + g);
                let r = g + o - f;
                md = min(md, dot(r, r));
            }
        }
    }
    return sqrt(md) * 2.0 - 1.0;
}

fn noiseByType(noiseKind: i32, p3: vec3f, p2: vec2f) -> f32 {
    if (noiseKind == 1) { return noiseSimplex3(p3); }
    if (noiseKind == 2) { return noiseSimplex2(p2); }
    if (noiseKind == 3) { return noisePerlin3(p3); }
    if (noiseKind == 4) { return noisePerlin2(p2); }
    if (noiseKind == 5) { return voronoi3(p3); }
    return 0.0;
}

fn noiseFbmScalar(p: vec3f, noiseKind: i32, octaves: i32) -> f32 {
    var amp = 0.5;
    var freq = 1.0;
    var sum = 0.0;
    var norm = 0.0;
    let p2 = p.xy;
    for (var o = 0; o < 4; o++) {
        if (o >= octaves) { break; }
        let n = noiseByType(noiseKind, p * freq, p2 * freq);
        sum += n * amp;
        norm += amp;
        amp *= 0.5;
        freq *= 2.0;
    }
    return sum / max(norm, 0.0001);
}

fn noiseFbmVec3(p: vec3f, noiseKind: i32, octaves: i32) -> vec3f {
    return vec3f(
        noiseFbmScalar(p, noiseKind, octaves),
        noiseFbmScalar(p + vec3f(19.19, 7.7, 3.1), noiseKind, octaves),
        noiseFbmScalar(p + vec3f(5.5, 13.3, 27.9), noiseKind, octaves),
    );
}

fn applyParticleNoise(p: ptr<function, Particle>, lifeT: f32, mode: i32) {
    let layerCount = i32(round(ub.noiseLayerCount));
    if (layerCount <= 0) { return; }
    for (var li = 0; li < 4; li = li + 1) {
        if (li >= layerCount) { break; }
        let a0 = ub.noiseLayers[li * 2];
        let b0 = ub.noiseLayers[li * 2 + 1];
        let nAmp = a0.z;
        let targets = i32(round(b0.y));
        if (a0.x < 0.5 || nAmp < 0.0001 || targets == 0) { continue; }
        let noiseKind = i32(round(a0.x));
        let octaves = i32(clamp(round(b0.x), 1.0, 4.0));
        let nSeed = b0.z;
        let seedOff = vec3f(nSeed * 0.173, nSeed * 0.319, nSeed * 0.547);
        let anim = vec3f(ub.time * a0.w, ub.time * a0.w * 0.71, lifeT * a0.w * 0.37);
        let sampleP = (*p).position * a0.y + seedOff + anim;
        let n = noiseFbmVec3(sampleP, noiseKind, octaves);
        let amp = nAmp;
        if ((targets & NOISE_TARGET_VELOCITY) != 0 && mode != 3 && mode != 4) {
            (*p).velocity += n * amp;
        }
        if ((targets & NOISE_TARGET_COLOR) != 0 && mode != 3) {
            (*p).color = clamp((*p).color + n * amp * 0.35, vec3f(0.0), vec3f(3.0));
        }
        if ((targets & NOISE_TARGET_SIZE) != 0) {
            (*p).size = max(0.0001, (*p).size + n.x * amp * 0.015);
        }
        if ((targets & NOISE_TARGET_OPACITY) != 0) {
            (*p).opacity = clamp((*p).opacity + n.y * amp * 0.3, 0.0, 1.0);
        }
        if ((targets & NOISE_TARGET_POSITION) != 0 && mode != 3 && mode != 4) {
            (*p).position += n * amp * ub.dt * 3.0;
        }
    }
}

@compute @workgroup_size(64)
fn updateParticles(@builtin(global_invocation_id) gid: vec3u) {
    let i = gid.x * 1024u + gid.y;
    if (i >= ub.count) { return; }

    var p = particles[i];
    let waiting = -1.0;

    if (p.life <= 0.0) {
        if (p.seed == 0.0) {
            let slot = f32(i) / max(f32(ub.count), 1.0);
            p.life = -slot * ub.emitSpread;
            p.seed = waiting;
            particles[i] = p;
            return;
        }
        if (p.seed < 0.0) {
            p.life += ub.dt;
            if (p.life < 0.0) {
                particles[i] = p;
                return;
            }
        }

        let r0 = rand1(i + u32(ub.time * 1000.0));
        let r1 = rand1(i * 17u + u32(ub.time * 413.0));
        let r2 = rand1(i * 31u + u32(ub.time * 97.0));
        let r3 = rand1(i * 59u);
        let r4 = rand1(i * 83u);
        let r5 = rand1(i * 97u);

        p.seed = f32(i + 1u) + ub.time * 131.0;
        p.maxLife = curveScalar(
            ub.lifeStartMin, ub.lifeStartMax, ub.lifeEndMin, ub.lifeEndMax,
            r0, ub.lifeRandom, 0.0, ub.lifeEasing,
        );
        if (p.maxLife <= 0.0) {
            p.maxLife = 0.0;
            p.life = 1.0;
        } else {
            p.life = p.maxLife;
        }

        let motion = i32(round(ub.motionMode));

        p.size = curveScalar(
            ub.sizeStartMin, ub.sizeStartMax, ub.sizeEndMin, ub.sizeEndMax,
            r1, ub.sizeRandom, 0.0, ub.sizeEasing,
        );

        if (motion == 4) {
            p.position = fluidSpawnWorld(r4, r5, r3);
        } else if (motion == 2 && ub.spawnRadius <= 0.0) {
            p.position = ub.emitterPos + boidsSpawnVolume(r4, r5, r3);
        } else if (ub.spawnRadius > 0.0 || motion == 2) {
            p.position = ub.emitterPos + spawnOffset(r4, r5, r3);
        } else {
            p.position = ub.emitterPos;
        }

        let mode = motion;

        if (mode == 1) {
            p.pathPhase = r0 * 6.2831853;
            p.pathSpread = r1;
            let tangent = samplePathTangent(0.0);
            let pathPos = samplePathPos(0.0);
            let offset = pathOffset(tangent, 0.0, p.pathPhase, p.pathSpread);
            var spawnPos = ub.emitterPos + pathPos + offset;
            if (ub.spawnRadius > 0.0) {
                spawnPos += spawnOffset(r4, r5, r3);
            }
            p.position = spawnPos;
            p.velocity = vec3f(0.0);
        } else if (mode == 2) {
            p.maxLife = 0.0;
            p.life = 1.0;
            p.pathPhase = 0.0;
            p.pathSpread = 0.0;
            let flockAngle = f32(i) / max(f32(ub.count), 1.0) * 6.2831853;
            let baseDir = normalize(vec3f(cos(flockAngle), 0.0, sin(flockAngle)));
            let jitter = vec3f(r2 - 0.5, (r3 - 0.5) * 0.15, r4 - 0.5) * 0.4;
            var dir = normalize(baseDir + jitter);
            p.velocity = dir * ub.boidsMaxSpeed * mix(0.75, 1.0, r1);
        } else if (mode == 3) {
            var rootXZ = vec2f(0.0);
            if (ub.spawnRadius > 0.0) {
                let r = ub.spawnRadius;
                rootXZ = vec2f((r4 - 0.5) * 2.0 * r, (r5 - 0.5) * 2.0 * r);
            }
            p.pathPhase = rootXZ.x;
            p.pathSpread = rootXZ.y;
            p.position = ub.emitterPos + vec3f(p.pathPhase, 0.0, p.pathSpread);
            p.velocity = vec3f(0.0);
            p.color = vec3f(1.0);
        } else if (mode == 4) {
            p.pathPhase = 0.0;
            p.pathSpread = 0.0;
            p.velocity = vec3f(0.0);
            mpmC[i] = mat3x3<f32>();
        } else {
            p.pathPhase = 0.0;
            p.pathSpread = 0.0;
            p.velocity = sampleVelocity(r0, r1, r2, 0.0);
        }

        p.opacity = curveScalar(
            ub.opacityStartMin, ub.opacityStartMax, ub.opacityEndMin, ub.opacityEndMax,
            r2, ub.opacityRandom, 0.0, ub.opacityEasing,
        );
        if (mode != 3) {
            p.color = curveColor(r3, r4, ub.colorRandom, ub.colorRandomBetween, 0.0, ub.colorEasing);
        }
        applyParticleNoise(&p, 0.0, mode);
    } else {
        let t = particleLifeT(p.life, p.maxLife);
        let r0 = rand1(i + u32(p.seed));
        let r1 = rand1(i * 17u + u32(p.seed * 13.0));
        let r2 = rand1(i * 31u + u32(p.seed * 29.0));
        let r3 = rand1(i * 59u + u32(p.seed * 41.0));

        p.size = curveScalar(
            ub.sizeStartMin, ub.sizeStartMax, ub.sizeEndMin, ub.sizeEndMax,
            r0, ub.sizeRandom, t, ub.sizeEasing,
        );
        p.opacity = curveScalar(
            ub.opacityStartMin, ub.opacityStartMax, ub.opacityEndMin, ub.opacityEndMax,
            r1, ub.opacityRandom, t, ub.opacityEasing,
        );

        let mode = i32(round(ub.motionMode));

        if (mode != 3) {
            p.color = curveColor(r2, r3, ub.colorRandom, ub.colorRandomBetween, t, ub.colorEasing);
        }

        if (mode == 1) {
            let tangent = samplePathTangent(t);
            let pathPos = samplePathPos(t);
            let offset = pathOffset(tangent, t, p.pathPhase, p.pathSpread);
            let pathBase = ub.emitterPos + pathPos + offset;
            p.velocity.y -= ub.gravity * ub.dt;
            p.velocity *= max(0.0, 1.0 - ub.drag * ub.dt);
            p.position = pathBase + p.velocity;
            applyParticleNoise(&p, t, mode);
            applyBoundsCollision(&p);
        } else if (mode == 2) {
            applyBoids(i, &p);
            if (ub.drag > 0.0) {
                p.velocity *= max(0.0, 1.0 - ub.drag * ub.dt);
            }
            p.position += p.velocity * ub.dt;
            applyParticleNoise(&p, t, mode);
            boidsEnforceBounds(&p);
        } else if (mode == 3) {
            applyHair(&p);
            applyParticleNoise(&p, t, mode);
        } else if (mode == 4) {
            // MLS-MPM grid passes handle advection (mpmG2P).
        } else {
            p.velocity *= max(0.0, 1.0 - ub.drag * ub.dt);
            p.velocity.y -= ub.gravity * ub.dt;
            p.position += p.velocity * ub.dt;
            applyParticleNoise(&p, t, mode);
            if (ub.selfCollide > 0.5) {
                applyFluidSelfCollide(i, &p);
                applyFluidSelfCollide(i, &p);
            }
            applyBoundsCollision(&p);
        }
        if (p.maxLife > 0.0) {
            p.life -= ub.dt;
        }
    }

    particles[i] = p;
}
